create extension if not exists "uuid-ossp";
create table if not exists users(id text primary key,email text unique not null,name text,vibe_vector jsonb default'{}',seed_venues text[] default'{}',seed_artists text[] default'{}',prefs jsonb default'{}',created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists venues(id text primary key,name text not null,neighborhood text,address text,description text,vibe_tags text[] default'{}',music_genres text[] default'{}',music_score float default 3,energy_score float default 3,dance_score float default 3,demo_score float default 3,crowd_desc text,hours text,img_color text default'#1a1a2e',visible boolean default true,created_at timestamptz default now());
create table if not exists user_venue_ratings(id uuid primary key default uuid_generate_v4(),user_id text references users(id) on delete cascade,venue_id text references venues(id),music_score float not null check(music_score between 1 and 5),energy_score float not null check(energy_score between 1 and 5),dance_score float not null check(dance_score between 1 and 5),demo_score float not null check(demo_score between 1 and 5),created_at timestamptz default now(),updated_at timestamptz default now(),unique(user_id,venue_id));
create table if not exists saved_venues(id uuid primary key default uuid_generate_v4(),user_id text references users(id) on delete cascade,venue_id text references venues(id),status text check(status in('want_to_visit','visited'))default'want_to_visit',created_at timestamptz default now(),unique(user_id,venue_id));
create table if not exists daily_recs(id uuid primary key default uuid_generate_v4(),user_id text references users(id) on delete cascade,venue_id text references venues(id),rec_date date not null,match_score int,user_action text check(user_action in('saved','not_tonight','visited','dismissed')),created_at timestamptz default now());
alter table users enable row level security;alter table user_venue_ratings enable row level security;alter table saved_venues enable row level security;alter table daily_recs enable row level security;
create policy"users_own"on users for all using(id=auth.uid()::text);create policy"ratings_own"on user_venue_ratings for all using(user_id=auth.uid()::text);create policy"saved_own"on saved_venues for all using(user_id=auth.uid()::text);create policy"recs_own"on daily_recs for all using(user_id=auth.uid()::text);create policy"venues_public_read"on venues for select using(visible=true);